const searchBlocks=document.querySelectorAll(".search-block");searchBlocks.length&&searchBlocks.forEach(s=>{const c=s.querySelector(".search-block__input"),t=s.querySelector(".search-block__results");c.addEventListener("input",e=>{e.currentTarget.value.length>0?(t.classList.add("is-open"),s.classList.add("is-active")):(t.classList.remove("is-open"),s.classList.remove("is-active"))}),document.addEventListener("click",e=>{const i=e.target.closest(".search-block__field"),l=e.target.closest(".search-block__results");!i&&!l&&(t.classList.remove("is-open"),s.classList.remove("is-active"))}),c.addEventListener("focus",e=>{e.currentTarget.value.length>0&&(t.classList.add("is-open"),s.classList.add("is-active"))})});
